exercise.solution_code:
#include <iostream>
#include <iomanip>
#include <cmath>

namespace physics::constants
{
    inline constexpr double kMinValid = 0.1;
    inline constexpr double kMaxValid = 100.0;
}

static bool isValidMeasurement(double v)
{
    double a = std::abs(v);
    return a >= physics::constants::kMinValid && a <= physics::constants::kMaxValid;
}

int main()
{
    static_assert(physics::constants::kMinValid < physics::constants::kMaxValid,
                  "kMinValid must be less than kMaxValid");

    double v1{}, v2{}, v3{}, v4{};
    std::cin >> v1 >> v2 >> v3 >> v4;

    std::cout << std::fixed << std::setprecision(2);

    int validCount = 0;

    if (isValidMeasurement(v1)) {
        std::cout << "Valid: " << v1 << "\n";
        ++validCount;
    }
    if (isValidMeasurement(v2)) {
        std::cout << "Valid: " << v2 << "\n";
        ++validCount;
    }
    if (isValidMeasurement(v3)) {
        std::cout << "Valid: " << v3 << "\n";
        ++validCount;
    }
    if (isValidMeasurement(v4)) {
        std::cout << "Valid: " << v4 << "\n";
        ++validCount;
    }

    if (validCount == 0)
        std::cout << "No valid measurements\n";

    return 0;
}
